"""Write generated files with rollback support."""

from __future__ import annotations

import re
import shutil
import tempfile
from dataclasses import dataclass
from pathlib import Path

from loguru import logger

from figma_flutter_agent.errors import GenerationError
from figma_flutter_agent.generator.dart.postprocess import process_generated_dart_source

_UTF8_ENCODING = "utf-8"

_CUSTOM_CODE_BLOCK_RE = re.compile(
    r"//\s*<\s*custom-code(?:\s*:\s*(?P<name>[\w.:+-]+))?\s*>\s*\n?"
    r"(?P<body>.*?)"
    r"//\s*</\s*custom-code(?:\s*:\s*(?P=name))?\s*>",
    re.DOTALL | re.IGNORECASE,
)
_AUTO_GENERATED_BLOCK_RE = re.compile(
    r"// <auto-generated>.*?// </auto-generated>",
    re.DOTALL,
)
_ORPHAN_NOISE_LINE_RE = re.compile(r"^[\s\)\}]+$")
_AGENT_GENERATED_BANNER = "// Generated by figma-flutter-agent"


def format_orphan_edit_message(
    relative_path: str,
    content: str,
    orphan_lines: list[int],
    *,
    max_lines: int = 3,
) -> str:
    """Build a human-readable message for edits outside preservation zones.

    Args:
        relative_path: Project-relative Dart file path.
        content: Existing file contents.
        orphan_lines: 1-based line numbers outside protected zones.
        max_lines: Maximum orphan line previews to include.

    Returns:
        Message suitable for logs or ``GenerationError``.
    """
    line_list = content.splitlines()
    previews: list[str] = []
    for line_no in orphan_lines[:max_lines]:
        if 1 <= line_no <= len(line_list):
            snippet = line_list[line_no - 1].strip()
            if len(snippet) > 72:
                snippet = f"{snippet[:69]}..."
            previews.append(f"L{line_no}: {snippet}")
    preview_suffix = f" Preview: {' | '.join(previews)}" if previews else ""
    numbers = ", ".join(str(line) for line in orphan_lines[:8])
    suffix = "..." if len(orphan_lines) > 8 else ""
    return (
        f"Manual edits outside preservation zones in {relative_path} "
        f"(lines: {numbers}{suffix}).{preview_suffix}"
    )


def _protected_line_numbers(content: str) -> set[int]:
    """Line numbers inside ``<auto-generated>`` or ``<custom-code>`` markers."""
    protected: set[int] = set()
    for pattern in (_AUTO_GENERATED_BLOCK_RE, _CUSTOM_CODE_BLOCK_RE):
        for match in pattern.finditer(content):
            start = content.count("\n", 0, match.start()) + 1
            end = content.count("\n", 0, match.end()) + 1
            protected.update(range(start, end + 1))
    return protected


def find_orphan_line_numbers(content: str) -> list[int]:
    """Return 1-based line numbers with user code outside preservation zones.

    Agent-generated Dart only marks the file header in ``<auto-generated>``; imports
    and widget bodies are still owned by the compiler. When the figma-flutter banner
    is present, only non-empty ``<custom-code>`` zones are user-editable — everything
    else is treated as agent territory (no orphan warnings on regeneration).
    """
    if _AGENT_GENERATED_BANNER in content:
        return []

    protected = _protected_line_numbers(content)
    orphans: list[int] = []
    for line_no, line in enumerate(content.splitlines(), start=1):
        stripped = line.strip()
        if not stripped or stripped.startswith("//"):
            continue
        if _ORPHAN_NOISE_LINE_RE.match(stripped):
            continue
        if line_no not in protected:
            orphans.append(line_no)
    return orphans


@dataclass(frozen=True)
class _WriteRecord:
    target: Path
    existed_before: bool


@dataclass(frozen=True)
class WriteBatch:
    """Pending write batch that can be committed or rolled back."""

    backup_dir: Path
    written: list[_WriteRecord]


def _custom_code_marker(name: str, *, closing: bool = False) -> str:
    suffix = f":{name}" if name else ""
    prefix = "/" if closing else ""
    return f"// <{prefix}custom-code{suffix}>"


def _leading_indent(line: str) -> str:
    return line[: len(line) - len(line.lstrip(" \t"))]


def _rebase_custom_code_indent(body: str, target_indent: str) -> str:
    """Shift preserved custom code so it aligns with the new file's zone indentation."""
    lines = body.splitlines()
    non_empty = [line for line in lines if line.strip()]
    if not non_empty:
        return body
    base_len = min(len(_leading_indent(line)) for line in non_empty)
    rebased: list[str] = []
    for line in lines:
        if not line.strip():
            rebased.append("")
            continue
        content = line[base_len:] if len(line) >= base_len else line.lstrip()
        rebased.append(f"{target_indent}{content}")
    return "\n".join(rebased)


def _custom_code_zone_indent(content: str, match: re.Match[str]) -> str:
    """Return indentation for lines inside a custom-code zone (marker line + one level)."""
    line_start = content.rfind("\n", 0, match.start()) + 1
    line_end = content.find("\n", match.start())
    if line_end == -1:
        line_end = len(content)
    marker_line = content[line_start:line_end]
    return f"{_leading_indent(marker_line)}  "


def extract_custom_code_blocks_ordered(content: str) -> list[tuple[str, str]] | None:
    """Extract custom-code blocks in source order as ``(zone_name, body)`` pairs."""
    matches = list(_CUSTOM_CODE_BLOCK_RE.finditer(content))
    if not matches:
        return None
    return [(match.group("name") or "", match.group("body").strip("\n")) for match in matches]


def extract_custom_code_blocks(content: str) -> dict[str, str] | None:
    """Extract all custom-code blocks keyed by zone name."""
    ordered = extract_custom_code_blocks_ordered(content)
    if ordered is None:
        return None
    blocks: dict[str, str] = {}
    for name, body in ordered:
        blocks[name] = body
    return blocks


def extract_custom_code(content: str) -> str | None:
    """Extract user code from the legacy unnamed custom-code block."""
    blocks = extract_custom_code_blocks(content)
    if blocks is None:
        return None
    return blocks.get("", next(iter(blocks.values()), ""))


def _insert_after_imports(content: str, block: str) -> str:
    """Insert a block after the last import/export line to preserve Dart import order."""
    if not block.strip():
        return content
    lines = content.splitlines()
    last_import = -1
    for index, line in enumerate(lines):
        stripped = line.strip()
        if stripped.startswith("import ") or stripped.startswith("export "):
            last_import = index
    if last_import < 0:
        return f"{block}\n{content}" if content else block
    head = lines[: last_import + 1]
    tail = lines[last_import + 1 :]
    return "\n".join([*head, "", block, "", *tail])


def _preserved_body_for_zone(
    zone_name: str,
    preserved_by_name: dict[str, str],
    legacy_role_bodies: dict[str, str],
) -> str:
    """Resolve preserved user code for a newly generated zone name."""
    if zone_name in preserved_by_name:
        return preserved_by_name[zone_name]
    from figma_flutter_agent.generator.custom_code_zones import legacy_role_from_zone

    role = legacy_role_from_zone(zone_name)
    if role is not None and role in legacy_role_bodies:
        return legacy_role_bodies[role]
    if role is not None:
        for key, body in preserved_by_name.items():
            if legacy_role_from_zone(key) == role:
                return body
    return ""


def merge_custom_code(new_content: str, existing_content: str) -> str:
    """Preserve existing custom-code blocks inside newly generated content."""
    preserved = extract_custom_code_blocks_ordered(existing_content)
    if preserved is None:
        return new_content

    if _CUSTOM_CODE_BLOCK_RE.search(new_content) is None:
        notes = _format_unmerged_blocks({name: body for name, body in preserved})
        return _insert_after_imports(new_content, notes) if notes else new_content

    from figma_flutter_agent.generator.custom_code_zones import (
        is_legacy_role_zone,
        legacy_role_from_zone,
    )

    preserved_by_name: dict[str, str] = {}
    legacy_role_bodies: dict[str, str] = {}
    positional_bodies: list[str] = []
    for name, body in preserved:
        preserved_by_name[name] = body
        positional_bodies.append(body)
        role = legacy_role_from_zone(name)
        if role is not None:
            legacy_role_bodies.setdefault(role, body)
        elif is_legacy_role_zone(name):
            legacy_role_bodies.setdefault(name, body)

    index = 0

    def _replace(match: re.Match[str]) -> str:
        nonlocal index
        name = match.group("name") or ""
        body = _preserved_body_for_zone(name, preserved_by_name, legacy_role_bodies)
        if not body.strip() and index < len(positional_bodies):
            body = positional_bodies[index]
        if index < len(positional_bodies):
            index += 1
        open_marker = _custom_code_marker(name)
        close_marker = _custom_code_marker(name, closing=True)
        if body.strip():
            zone_indent = _custom_code_zone_indent(new_content, match)
            body = _rebase_custom_code_indent(body, zone_indent)
        inner = f"\n{body}\n" if body.strip() else "\n"
        return f"{open_marker}{inner}{close_marker}"

    merged = _CUSTOM_CODE_BLOCK_RE.sub(_replace, new_content)
    unmatched = positional_bodies[index:]
    notes = _format_unmerged_blocks(
        {f"preserved-{idx}": body for idx, body in enumerate(unmatched, start=1)}
    )
    if notes:
        merged = _insert_after_imports(merged, notes)
    return merged


def _format_unmerged_blocks(blocks: dict[str, str]) -> str:
    """Serialize unmatched custom-code zones so user logic is never dropped."""
    if not blocks:
        return ""
    sections: list[str] = []
    for name, body in blocks.items():
        open_marker = _custom_code_marker(name)
        close_marker = _custom_code_marker(name, closing=True)
        inner = f"\n{body}\n" if body.strip() else "\n"
        sections.append(f"{open_marker}{inner}{close_marker}")
    return "\n\n".join(sections)


def read_text_file(path: Path) -> str:
    """Read a project text file as UTF-8 (CJK and other non-ASCII safe on Windows)."""
    return path.read_text(encoding=_UTF8_ENCODING)


def _atomic_write_text(target: Path, content: str) -> None:
    tmp_path = target.with_name(f"{target.name}.tmp")
    try:
        tmp_path.write_text(content, encoding=_UTF8_ENCODING)
        tmp_path.replace(target)
    except OSError:
        if tmp_path.exists():
            tmp_path.unlink(missing_ok=True)
        raise


class DartWriter:
    """Write generated Dart files into a Flutter project."""

    def __init__(
        self,
        project_dir: Path,
        *,
        enable_backup: bool = True,
        strict_preservation: bool = False,
    ) -> None:
        self._project_dir = project_dir
        self._project_dir_resolved = project_dir.resolve()
        self._enable_backup = enable_backup
        self._strict_preservation = strict_preservation
        self._orphan_warnings_emitted: set[str] = set()

    def _finalize_dart_content(self, relative_path: str, content: str) -> str:
        if not relative_path.endswith(".dart"):
            return content
        normalized = relative_path.replace("\\", "/")
        from figma_flutter_agent.generator.dart.file_parts import relocate_directives_to_header
        from figma_flutter_agent.generator.dart.syntax_repairs import apply_llm_dart_syntax_repairs
        from figma_flutter_agent.generator.planned_dart import (
            _sanitize_ingested_widget_source,
            _skips_codegen_ast_pass,
        )

        if normalized.startswith("lib/widgets/"):
            return _sanitize_ingested_widget_source(content, widget_path=normalized)
        if normalized.startswith("test/capture/"):
            from figma_flutter_agent.generator.capture_screen_test import (
                finalize_capture_screen_test_content,
            )

            return finalize_capture_screen_test_content(content)
        if _skips_codegen_ast_pass(normalized, content):
            return relocate_directives_to_header(apply_llm_dart_syntax_repairs(content))
        return process_generated_dart_source(content)

    def _safe_target_path(self, relative_path: str) -> Path:
        candidate = (self._project_dir / relative_path).resolve()
        if not candidate.is_relative_to(self._project_dir_resolved):
            raise GenerationError(f"Refusing to write outside project directory: {relative_path}")
        return candidate

    def write_files(self, files: dict[str, str]) -> WriteBatch | None:
        """Write generated files and return a batch that must be committed or rolled back.

        Args:
            files: Relative project paths mapped to generated file contents.

        Returns:
            Write batch when backup is enabled, otherwise ``None``.
        """
        self._orphan_warnings_emitted.clear()
        orphan_reports: list[tuple[str, str, list[int]]] = []

        def _stage_file(relative_path: str, content: str) -> str:
            target = self._safe_target_path(relative_path)
            target.parent.mkdir(parents=True, exist_ok=True)
            content_to_write = content
            normalized_path = relative_path.replace("\\", "/")
            if target.exists() and not normalized_path.startswith("test/"):
                existing_content = read_text_file(target)
                orphan_lines = find_orphan_line_numbers(existing_content)
                if orphan_lines:
                    orphan_reports.append((relative_path, existing_content, orphan_lines))
                content_to_write = merge_custom_code(content, existing_content)
            return self._finalize_dart_content(relative_path, content_to_write)

        if not self._enable_backup:
            for relative_path, content in files.items():
                target = self._safe_target_path(relative_path)
                _atomic_write_text(target, _stage_file(relative_path, content))
            self._emit_orphan_warnings(orphan_reports)
            return None

        backup_dir = Path(tempfile.mkdtemp(prefix="figma-flutter-backup-"))
        written: list[_WriteRecord] = []
        try:
            for relative_path, content in files.items():
                target = self._safe_target_path(relative_path)
                existed_before = target.exists()
                if existed_before:
                    backup_target = backup_dir / relative_path
                    backup_target.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(target, backup_target)

                _atomic_write_text(target, _stage_file(relative_path, content))
                written.append(_WriteRecord(target=target, existed_before=existed_before))
        except OSError as exc:
            logger.error("Writing failed, executing rollback...")
            self._restore_backup(backup_dir, written)
            shutil.rmtree(backup_dir, ignore_errors=True)
            raise GenerationError(f"Failed to write generated files: {exc}") from exc

        self._emit_orphan_warnings(orphan_reports)
        return WriteBatch(backup_dir=backup_dir, written=written)

    def commit_batch(self, batch: WriteBatch | None) -> None:
        """Delete backup artifacts after validation succeeds."""
        if batch is None:
            return
        shutil.rmtree(batch.backup_dir, ignore_errors=True)

    def rollback_batch(self, batch: WriteBatch | None) -> None:
        """Restore files from backup after validation or pubspec merge failure."""
        if batch is None:
            return
        self._restore_backup(batch.backup_dir, batch.written)
        shutil.rmtree(batch.backup_dir, ignore_errors=True)

    def _emit_orphan_warnings(self, reports: list[tuple[str, str, list[int]]]) -> None:
        """Log preservation-zone conflicts once per batch (strict mode raises immediately)."""
        if not reports:
            return
        for relative_path, existing_content, orphan_lines in reports:
            message = format_orphan_edit_message(
                relative_path,
                existing_content,
                orphan_lines,
            )
            if self._strict_preservation:
                raise GenerationError(message)
        if len(reports) == 1:
            relative_path, existing_content, orphan_lines = reports[0]
            message = format_orphan_edit_message(
                relative_path,
                existing_content,
                orphan_lines,
            )
            logger.warning("{}; regeneration may overwrite them", message)
            return
        examples = ", ".join(
            f"{path} ({len(lines)} line(s))"
            for path, _content, lines in reports[:4]
        )
        suffix = "..." if len(reports) > 4 else ""
        logger.warning(
            "Manual edits outside <custom-code> in {} generated file(s) "
            "(regeneration may overwrite). Examples: {}{}",
            len(reports),
            examples,
            suffix,
        )

    def _guard_orphan_edits(self, relative_path: str, existing_content: str) -> None:
        """Legacy hook; prefer batching via :meth:`_emit_orphan_warnings`."""
        orphan_lines = find_orphan_line_numbers(existing_content)
        if not orphan_lines:
            return
        message = format_orphan_edit_message(relative_path, existing_content, orphan_lines)
        if self._strict_preservation:
            raise GenerationError(message)
        if relative_path in self._orphan_warnings_emitted:
            return
        self._orphan_warnings_emitted.add(relative_path)
        logger.warning("{}; regeneration may overwrite them", message)

    def _restore_backup(self, backup_dir: Path, written: list[_WriteRecord]) -> None:
        restored: list[str] = []
        for record in written:
            try:
                relative = record.target.relative_to(self._project_dir)
                backup_source = backup_dir / relative
                if backup_source.exists():
                    shutil.copy2(backup_source, record.target)
                elif not record.existed_before and record.target.exists():
                    record.target.unlink()
                restored.append(str(relative))
            except OSError as exc:
                logger.exception(
                    "Rollback step failed for {}: {}",
                    record.target,
                    exc,
                )
                partial = ", ".join(restored) if restored else "none"
                raise GenerationError(
                    f"Rollback failed after partial restore (restored: {partial}); "
                    f"failed on {record.target}: {exc}"
                ) from exc
